package model
type CourseModel struct { CourseID int `json:"course_id"` Name string `json:"name"` //课程名称 Introduction string `json:"introduction"` //课程介绍 Price int `json:"price"` //课程价格，单位元 Duration int `json:"duration"` //课程时长，单位分钟 Image string `json:"image"` //课程图片-方行 ImageCircle string `json:"image_circle"` //课程图片-圆形 MarketPrice int `json:"market_price"` //课程市场价格，单位元 ChargeType int `json:"charge_type"` //1=付费，2=免费体验课 Type int `json:"type"` //课程类型 }
const ( Enum_Course_ChargeType_Paid = iota + 1 // 1 付费 Enum_Course_ChargeType_FreeTrial // 2 免费体验课 )
const ( Enum_Course_Type_Trial = iota // 0=基础 Enum_Course_Type_Intermediate // 1=中级 Enum_Course_Type_Advanced // 2=高级 Enum_Course_Type_Senior // 3=资深 Enum_Course_Type_Specialty // 4=特色 )

package model
type CourseModel struct { CourseID int `json:"course_id"` Name string `json:"name"` //课程名称 Introduction string `json:"introduction"` //课程介绍 Price int `json:"price"` //课程价格，单位元 Duration int `json:"duration"` //课程时长，单位分钟 Image string `json:"image"` //课程图片-方行 ImageCircle string `json:"image_circle"` //课程图片-圆形 MarketPrice int `json:"market_price"` //课程市场价格，单位元 ChargeType int `json:"charge_type"` //1=付费，2=免费体验课 Type int `json:"type"` //课程类型 }
const ( Enum_Course_ChargeType_Paid = iota + 1 // 1 付费 Enum_Course_ChargeType_FreeTrial // 2 免费体验课 )
const ( Enum_Course_Type_Trial = iota // 0=基础 Enum_Course_Type_Intermediate // 1=中级 Enum_Course_Type_Advanced // 2=高级 Enum_Course_Type_Senior // 3=资深 Enum_Course_Type_Specialty // 4=特色 )

package model
// 体验课预生成管理模型 // 用于匹配 trail_manage 表的字段 type PreTrailManageModel struct { ID int64 `json:"id"` // 主键ID UserPhone string `json:"user_phone"` // 用户手机号（微信绑定） TrainingNeed string `json:"training_need"` // 训练需求（增肌/减脂/塑形/普拉提/拳击/体态/康复/上门/其他） GymID int `json:"gym_id"` // 门店ID CoachID int `json:"coach_id"` // 教练ID LessonDate int64 `json:"lesson_date"` // 体验课日期 LessonTimeBeg int64 `json:"lesson_time_beg"` // 体验课开始时间 LessonTimeEnd int64 `json:"lesson_time_end"` // 体验课结束时间 Price int `json:"price"` // 体验课价格（单位：元） LinkToken string `json:"link_token"` // 生成的链接token LinkStatus int `json:"link_status"` // 生成的链接状态，链接状态：0-待使用，1-已使用，2-已过期 PackageId string `json:"package_id"` // 关联的课包id Remark string `json:"remark"` // 备注 CreatedBy string `json:"created_by"` // 创建人（顾问） CreatedTs int64 `json:"created_ts"` // 创建时间 UpdatedTs int64 `json:"updated_ts"` // 更新时间 }
// LinkStatus 枚举类型 const ( Enum_Link_Status_Pending int = iota // 0 - 待使用 Enum_Link_Status_Used // 1 - 已使用 Enum_Link_Status_Cancel // 2 - 已取消 Enum_Link_Status_Expired // 3 - 已过期 )

package model
type CoachModel struct { CoachID int `json:"coach_id"` //教练id GymID int `json:"gym_id"` //健身房id GymIDs string `json:"gym_ids"` //单个教练多门店，榜单健身房id数组 CoachName string `json:"coach_name"` //教练名称 Avatar string `json:"avatar"` //教练头像url Bio string `json:"bio"` //教练简介 Rating int `json:"rating"` //教练评分 RecReason string `json:"rec_reason"` //教练推荐原因 Priority int `json:"priority"` //教练优先级 CourseIdList string `json:"course_id_list"` //教练可上课程列表，英文逗号分割 BannerPicList string `json:"banner_pic_list"` //教练详情页顶部banner图（英文逗号分割） GoodAt string `json:"good_at"` //教练擅长领域 Phone string `json:"phone"` //手机号 CircleAvatar string `json:"circle_avatar"` //教练圆形头像url JoinTs int64 `json:"join_ts"` //教练入驻时间（后台配置生效） BTestCoach bool `json:"b_test_coach"` //是否测试教练，外网白名单测试专用 QualifyType int `json:"qualify_type"` //教练资质类型 (参考枚举 Enum_Coach_QualifyType) SkillCertification string `json:"skill_certification"` //教练的技能认证（英文逗号分割） Style string `json:"style"` //教练风格（英文逗号分割） YearsOfWork string `json:"years_of_work"` //从业时长 TotalCompleteLesson string `json:"total_complete_lesson"` //累计上课节数 CanShow int `json:"can_show"` //是否可以在平台展示，0=不可展示 1=可展示 CloneLessonUnavaSwitch int `json:"clone_lesson_unava_switch"` //是否把可约状态同步到下周 0=默认同步 }
const ( Enum_Coach_QualifyType_Basic int = iota + 1 // 1 = 基础 Enum_Coach_QualifyType_Intermediate // 2 = 中级 Enum_Coach_QualifyType_Advanced // 3 = 高级 Enum_Coach_QualifyType_Senior // 4 = 资深 )
const ( Enum_Coach_Can_Show_YES int = iota // 0 = 默认可以在平台展示 Enum_Coach_Can_Show_NO // 1 = 不可在平台展示 )
const ( Enum_Coach_Clone_Lesson_Unavaliable_YES int = iota // 0 = 默认同步 Enum_Coach_Clone_Lesson_Unavaliable_NO // 1 = 不同步下周 )

