type CoursePackageRenewalInterfaceImp struct{}

const course_package_renewal_tableName = "course_package_renewal"

// AddRenewalRecord 添加续费记录
func (imp *CoursePackageRenewalInterfaceImp) AddRenewalRecord(renewalRecord *model.CoursePackageRenewalModel) error {
	cli := db.Get()

	renewalRecord.CreatedAt = time.Now()
	renewalRecord.UpdatedAt = time.Now()

	err := cli.Table(course_package_renewal_tableName).Create(renewalRecord).Error
	if err != nil {
		fmt.Printf("add renewal record err, packageId:%s orderId:%s err:%+v\n", 
			renewalRecord.PackageID, renewalRecord.OrderID, err)
		return err
	}

	return nil
}

// GetRenewalRecordsByPackageID 根据课包ID获取续费记录列表
func (imp *CoursePackageRenewalInterfaceImp) GetRenewalRecordsByPackageID(packageID string) ([]*model.CoursePackageRenewalModel, error) {
	cli := db.Get()

	var records []*model.CoursePackageRenewalModel
	err := cli.Table(course_package_renewal_tableName).
		Where("package_id = ?", packageID).
		Order("renewal_time DESC").
		Find(&records).Error

	if err != nil {
		fmt.Printf("get renewal records by packageId err, packageId:%s err:%+v\n", packageID, err)
		return nil, err
	}

	return records, nil
}

// GetRenewalRecordByOrderID 根据订单ID获取续费记录
func (imp *CoursePackageRenewalInterfaceImp) GetRenewalRecordByOrderID(orderID string) (*model.CoursePackageRenewalModel, error) {
	cli := db.Get()

	var record model.CoursePackageRenewalModel
	err := cli.Table(course_package_renewal_tableName).
		Where("order_id = ?", orderID).
		First(&record).Error

	if err != nil {
		if gorm.IsRecordNotFoundError(err) {
			return nil, nil
		}
		fmt.Printf("get renewal record by orderId err, orderId:%s err:%+v\n", orderID, err)
		return nil, err
	}

	return &record, nil
}

// GetTotalRenewalAmountByPackageID 统计课包的总续费金额
func (imp *CoursePackageRenewalInterfaceImp) GetTotalRenewalAmountByPackageID(packageID string) (int, error) {
	cli := db.Get()

	var totalAmount int
	err := cli.Table(course_package_renewal_tableName).
		Where("package_id = ?", packageID).
		Select("COALESCE(SUM(payment_amount), 0)").
		Row().Scan(&totalAmount)

	if err != nil {
		fmt.Printf("get total renewal amount by packageId err, packageId:%s err:%+v\n", packageID, err)
		return 0, err
	}

	return totalAmount, nil
}

// GetTotalRenewalCourseCntByPackageID 统计课包的总续费课程数
func (imp *CoursePackageRenewalInterfaceImp) GetTotalRenewalCourseCntByPackageID(packageID string) (int, error) {
	cli := db.Get()

	var totalCnt int
	err := cli.Table(course_package_renewal_tableName).
		Where("package_id = ?", packageID).
		Select("COALESCE(SUM(course_cnt), 0)").
		Row().Scan(&totalCnt)

	if err != nil {
		fmt.Printf("get total renewal course cnt by packageId err, packageId:%s err:%+v\n", packageID, err)
		return 0, err
	}

	return totalCnt, nil
