func (imp *CoursePackageInterfaceImp) AddCourseCnt(packageId string, cnt int) error {
	cli := db.Get()

	err := cli.Transaction(func(tx *gorm.DB) error {
		// 首先获取当前的课包信息
		var coursePackage model.CoursePackageModel
		err := cli.Table(course_package_tableName).Where("package_id = ?", packageId).First(&coursePackage).Error
		if err != nil {
			fmt.Printf("get course package err, packageId:%s err:%+v\n", packageId, err)
			tx.Rollback()
			return err
		}

		// 更新课程数量
		err = cli.Table(course_package_tableName).Model(&model.CoursePackageModel{}).Where("package_id = ?", packageId).UpdateColumn("remain_cnt", gorm.Expr("remain_cnt + ?", cnt)).Error
		if err != nil {
			fmt.Printf("update remain_cnt err, packageId:%s cnt:%d\n", packageId, cnt)
			tx.Rollback()
			return err
		}

		err = cli.Table(course_package_tableName).Model(&model.CoursePackageModel{}).Where("package_id = ?", packageId).UpdateColumn("total_cnt", gorm.Expr("total_cnt + ?", cnt)).Error
		if err != nil {
			fmt.Printf("update total_cnt err, packageId:%s cnt:%d\n", packageId, cnt)
			tx.Rollback()
			return err
		}

		// 更新续费记录
		renewalRecord := model.RenewalRecord{
			RenewalTime: time.Now().Unix(),
			CourseCnt: cnt,
			PaymentAmount: 0, // 这里可以根据实际支付金额设置
			OrderID: "", // 这里可以根据实际订单ID设置
			Operator: "system",
		}

		// 解析现有的续费记录
		var existingRecords []model.RenewalRecord
		if coursePackage.RenewalRecords != "" {
			err = json.Unmarshal([]byte(coursePackage.RenewalRecords), &existingRecords)
			if err != nil {
				fmt.Printf("unmarshal renewal records err, packageId:%s err:%+v\n", packageId, err)
				// 如果解析失败，重新初始化记录列表
				existingRecords = []model.RenewalRecord{}
			}
		}

		// 添加新的续费记录
		existingRecords = append(existingRecords, renewalRecord)
		renewalRecordsJSON, err := json.Marshal(existingRecords)
		if err != nil {
			fmt.Printf("marshal renewal records err, packageId:%s err:%+v\n", packageId, err)
			tx.Rollback()
			return err
		}

		// 更新续费记录字段
		err = cli.Table(course_package_tableName).Model(&model.CoursePackageModel{}).Where("package_id = ?", packageId).UpdateColumn("renewal_records", string(renewalRecordsJSON)).Error
		if err != nil {
			fmt.Printf("update renewal_records err, packageId:%s err:%+v\n", packageId, err)
			tx.Rollback()
			return err
		}

		return nil
	})
	return err
}

