import (
	"fmt"
	"github.com/xionghengheng/ff_plib/db/model"
)

// ExampleCoursePackageRenewal 课包续费功能使用示例
func ExampleCoursePackageRenewal() {
	// 获取DAO实例
	coursePackageDao := &CoursePackageInterfaceImp{}
	renewalDao := &CoursePackageRenewalInterfaceImp{}

	// 示例：课包续费
	packageID := "user123_1700000000"
	courseCnt := 10
	paymentAmount := 50000 // 500元（分）
	orderID := "order_20250322160827"
	operator := "system"

	// 1. 增加课包课程数量并记录续费信息
	err := coursePackageDao.AddCourseCnt(packageID, courseCnt, paymentAmount, orderID, operator)
	if err != nil {
		fmt.Printf("续费失败: %v\n", err)
		return
	}
	fmt.Println("续费成功！")

	// 2. 查询该课包的续费记录
	renewalRecords, err := renewalDao.GetRenewalRecordsByPackageID(packageID)
	if err != nil {
		fmt.Printf("查询续费记录失败: %v\n", err)
		return
	}

	fmt.Printf("课包 %s 的续费记录:\n", packageID)
	for i, record := range renewalRecords {
		fmt.Printf(" %d. 时间: %s, 课程数: %d, 金额: %d分, 订单: %s, 操作人: %s\n", 
			i+1, record.RenewalTime.Format("2006-01-02 15:04:05"), 
			record.CourseCnt, record.PaymentAmount, record.OrderID, record.Operator)
	}

	// 3. 统计总续费金额和课程数
	totalAmount, err := renewalDao.GetTotalRenewalAmountByPackageID(packageID)
	if err != nil {
		fmt.Printf("统计续费金额失败: %v\n", err)
		return
	}

	totalCourseCnt, err := renewalDao.GetTotalRenewalCourseCntByPackageID(packageID)
	if err != nil {
		fmt.Printf("统计续费课程数失败: %v\n", err)
		return
	}

	fmt.Printf("总续费金额: %d分 (%.2f元)\n", totalAmount, float64(totalAmount)/100)
	fmt.Printf("总续费课程数: %d节\n", totalCourseCnt)

	// 4. 根据订单ID查询续费记录
	renewalRecord, err := renewalDao.GetRenewalRecordByOrderID(orderID)
	if err != nil {
		fmt.Printf("根据订单查询续费记录失败: %v\n", err)
		return
	}

	if renewalRecord != nil {
		fmt.Printf("订单 %s 的续费记录: 课程数 %d, 金额 %d分\n", 
			orderID, renewalRecord.CourseCnt, renewalRecord.PaymentAmount)
	}
}","instruction":"创建课包续费功能的使用示例，展示如何调用新的续费接口进行续费操作和查询","apply_mode":"apply_only"}},"timestamp":1774167073,"type":"TOOL_CALL_ARGS"}

