{"rawEvent":{"message_id":"019d1499863e7305a07cfd7d5e05559a","conversation_id":"019be14c5d6378f3bc72b4c0e8d25495","tool_call_id":"call_b62a8a80-4f34-4ffc-a12e-db011083b9c1","document":{"file_path":"/Users/derickwu/Documents/codespace/ff_plib/db/dao/dao.go","sub_content":"dao.go","sub_content_event":"open_editor","sub_content_event_value":"/Users/derickwu/Documents/codespace/ff_plib/db/dao/dao.go","sub_content_tip":"/Users/derickwu/Documents/codespace/ff_plib/db/dao/dao.go","old_string":"// GetRenewalRecordByOrderID 根据订单ID获取续费记录
func (imp *CoursePackageRenewalInterfaceImp) GetRenewalRecordByOrderID(orderID string) (*model.CoursePackageRenewalModel, error) {
	cli := db.Get()

	var record model.CoursePackageRenewalModel
