		return nil, err
	}

	return &record, nil
}

// GetRenewalRecordsByCourseID 根据课程ID获取续费记录列表
func (imp *CoursePackageRenewalInterfaceImp) GetRenewalRecordsByCourseID(courseID int) ([]*model.CoursePackageRenewalModel, error) {
	cli := db.Get()

	var records []*model.CoursePackageRenewalModel
	err := cli.Table(course_package_renewal_tableName).
		Where("course_id = ?", courseID).
		Order("renewal_time DESC").
		Find(&records).Error

	if err != nil {
		fmt.Printf("get renewal records by courseId err, courseId:%d err:%+v\n", courseID, err)
		return nil, err
	}

	return records, nil
}

// GetRenewalRecordsByCoachID 根据教练ID获取续费记录列表
func (imp *CoursePackageRenewalInterfaceImp) GetRenewalRecordsByCoachID(coachID int) ([]*model.CoursePackageRenewalModel, error) {
	cli := db.Get()

	var records []*model.CoursePackageRenewalModel
	err := cli.Table(course_package_renewal_tableName).
		Where("coach_id = ?", coachID).
		Order("renewal_time DESC").
		Find(&records).Error

	if err != nil {
		fmt.Printf("get renewal records by coachId err, coachId:%d err:%+v\n", coachID, err)
		return nil, err
	}

	return records, nil
}

// GetTotalRenewalAmountByCourseID 统计课程的总续费金额
func (imp *CoursePackageRenewalInterfaceImp) GetTotalRenewalAmountByCourseID(courseID int) (int, error) {
	cli := db.Get()

	var totalAmount int
	err := cli.Table(course_package_renewal_tableName).
		Where("course_id = ?", courseID).
		Select("COALESCE(SUM(payment_amount), 0)").
		Row().Scan(&totalAmount)

	if err != nil {
		fmt.Printf("get total renewal amount by courseId err, courseId:%d err:%+v\n", courseID, err)
		return 0, err
	}

	return totalAmount, nil
}

