	}
	fmt.Printf("\n课程 %d 的续费记录数量: %d\n", courseId, len(courseRenewals))

	// 6. 根据教练ID查询续费记录
	coachRenewals, err := renewalDao.GetRenewalRecordsByCoachID(coachId)
	if err != nil {
