	fmt.Printf("教练 %d 的续费记录数量: %d\n", coachId, len(coachRenewals))

	// 7. 统计课程和教练的续费数据
	courseTotalAmount, err := renewalDao.GetTotalRenewalAmountByCourseID(courseId)
	if err != nil {
