		return
	}

	coachTotalCnt, err := renewalDao.GetTotalRenewalCourseCntByCoachID(coachId)
	if err != nil {
		fmt.Printf("统计教练续费课程数失败: %v\n", err)
		return
	}

	fmt.Printf("\n课程 %d 统计: 总续费金额 %d分, 总续费课程数 %d节\n", courseId, courseTotalAmount, courseTotalCnt)
	fmt.Printf("教练 %d 统计: 总续费金额 %d分, 总续费课程数 %d节\n", coachId, coachTotalAmount, coachTotalCnt)
}","apply_mode":"apply_only"}},"timestamp":1774167210,"type":"TOOL_CALL_ARGS"}

