package model

import "time"

// CoursePackageRenewalModel 课包续费记录模型
type CoursePackageRenewalModel struct {
	ID            int64     `json:"id" gorm:"primary_key;AUTO_INCREMENT"` // 主键
	PackageID     string    `json:"package_id" gorm:"type:varchar(100);not null;index:idx_package_id"` // 课包ID，关联CoursePackageModel
	RenewalTime   time.Time `json:"renewal_time" gorm:"type:datetime;not null;index:idx_renewal_time"` // 续费时间
	CourseCnt     int       `json:"course_cnt" gorm:"type:int;not null"` // 续费课程数量
	PaymentAmount int       `json:"payment_amount" gorm:"type:int;not null"` // 续费金额（分）
	OrderID       string    `json:"order_id" gorm:"type:varchar(100);not null;index:idx_order_id"` // 订单ID
	Operator      string    `json:"operator" gorm:"type:varchar(50);not null"` // 操作人（系统或管理员）
	CreatedAt     time.Time `json:"created_at" gorm:"type:datetime;not null;default:CURRENT_TIMESTAMP"` // 创建时间
	UpdatedAt     time.Time `json:"updated_at" gorm:"type:datetime;not null;default:CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP"` // 更新时间
}

// TableName 返回表名
func (CoursePackageRenewalModel) TableName() string {
	return "course_package_renewal"
}

