	UpdateSingleLesson(uid int64, lessonId string, mapUpdates map[string]interface{}) error
	GetSingleLessonListFinishNotSendMsgWriteComment(nowTs int64, limit int) ([]model.CoursePackageSingleLessonModel, error)
