{"rawEvent":{"message_id":"019d149e30e27e3b93c4ee7483305ba6","conversation_id":"019be14c5d6378f3bc72b4c0e8d25495","tool_call_id":"tooluse_oqKQfgJLLIVprIr71KMjeX","document":{"file_path":"/Users/derickwu/Documents/codespace/ff_plib/db/dao/dao.go","sub_content":"dao.go","sub_content_event":"open_editor","sub_content_event_value":"/Users/derickwu/Documents/codespace/ff_plib/db/dao/dao.go","sub_content_tip":"/Users/derickwu/Documents/codespace/ff_plib/db/dao/dao.go","old_string":"// GetRenewalRecordsByPackageID 根据课包ID获取续费记录列表
func (imp *CoursePackageRenewalInterfaceImp) GetRenewalRecordsByPackageID(packageID string) ([]*model.CoursePackageRenewalModel, error) {
	cli := db.Get()

	var records []*model.CoursePackageRenewalModel
	err := cli.Table(course_package_renewal_tableName).
		Where("package_id = ?", packageID).
		Order("renewal_time DESC").
