func (imp *CoursePackageInterfaceImp) AddCourseCnt(packageId string, cnt int, paymentAmount int, orderId string, operator string, courseId int, coachId int) error {
	cli := db.Get()

	err := cli.Transaction(func(tx *gorm.DB) error {
		// 首先获取当前的课包信息
		var coursePackage model.CoursePackageModel
		err := cli.Table(course_package_tableName).Where("package_id = ?", packageId).First(&coursePackage).Error
		if err != nil {
			fmt.Printf("get course package err, packageId:%s err:%+v\n", packageId, err)
			tx.Rollback()
			return err
		}

		// 更新课程数量
		err = cli.Table(course_package_tableName).Model(&model.CoursePackageModel{}).Where("package_id = ?", packageId).UpdateColumn("remain_cnt", gorm.Expr("remain_cnt + ?", cnt)).Error
		if err != nil {
			fmt.Printf("update remain_cnt err, packageId:%s cnt:%d\n", packageId, cnt)
			tx.Rollback()
			return err
		}

		err = cli.Table(course_package_tableName).Model(&model.CoursePackageModel{}).Where("package_id = ?", packageId).UpdateColumn("total_cnt", gorm.Expr("total_cnt + ?", cnt)).Error
		if err != nil {
			fmt.Printf("update total_cnt err, packageId:%s cnt:%d\n", packageId, cnt)
			tx.Rollback()
			return err
		}

		// 创建续费记录
		renewalRecord := &model.CoursePackageRenewalModel{
			PackageID:     packageId,
			CourseId:      courseId,
			CoachId:       coachId,
			RenewalTime:   time.Now(),
			CourseCnt:     cnt,
			PaymentAmount: paymentAmount,
			OrderID:       orderId,
			Operator:      operator,
		}

		// 添加续费记录到续费表
		renewalImp := &CoursePackageRenewalInterfaceImp{}
		err = renewalImp.AddRenewalRecord(renewalRecord)
		if err != nil {
			fmt.Printf("add renewal record err, packageId:%s orderId:%s err:%+v\n", packageId, orderId, err)
			tx.Rollback()
			return err
		}

		return nil
	})
	return err
}

