// CoursePackageRenewalInterfaceImp 课包续费记录接口实现
type CoursePackageRenewalInterfaceImp struct{}

const course_package_renewal_tableName = "course_package_renewal"

// AddRenewalRecord 添加续费记录
func (imp *CoursePackageRenewalInterfaceImp) AddRenewalRecord(renewalRecord *model.CoursePackageRenewalModel) error {
	cli := db.Get()

	renewalRecord.CreatedAt = time.Now()
	renewalRecord.UpdatedAt = time.Now()

	err := cli.Table(course_package_renewal_tableName).Create(renewalRecord).Error
	if err != nil {
		fmt.Printf("add renewal record err, packageId:%s orderId:%s err:%+v\n",
			renewalRecord.PackageID, renewalRecord.OrderID, err)
		return err
	}

	return nil
}

// GetRenewalRecordsByPackageID 根据课包ID获取续费记录列表
func (imp *CoursePackageRenewalInterfaceImp) GetRenewalRecordsByPackageID(packageID string) ([]*model.CoursePackageRenewalModel, error) {
	cli := db.Get()

	var records []*model.CoursePackageRenewalModel
	err := cli.Table(course_package_renewal_tableName).
		Where("package_id = ?", packageID).
		Order("renewal_time DESC").
		Find(&records).Error

	if err != nil {
		fmt.Printf("get renewal records by packageId err, packageId:%s err:%+v\n", packageID, err)
		return nil, err
	}

	return records, nil
}

