// PreTrailManageInterface 体验课管理数据模型接口
type PreTrailManageInterface interface {
	// 添加体验课记录
	AddTrailManage(trail *model.PreTrailManageModel) error

	// 根据ID获取体验课记录
	GetTrailManageById(id int64) (*model.PreTrailManageModel, error)

