package comm

import (
	"fmt"
	"github.com/xionghengheng/ff_plib/db/dao"
	"github.com/xionghengheng/ff_plib/db/model"
	"os"
	"path"
	"runtime"
	"sort"
	"strconv"
	"strings"
	"time"
)

func genOrderId(productType int, ts int64) string {
	return fmt.Sprintf("%dFUNFIT%d", productType, ts)
}

func genPackageOrderId(productType int, ts int64, gymId int, coachId int, courseId int) string {
	return fmt.Sprintf("%dFUNFIT%d_%d_%d_%d", productType, ts, gymId, coachId, courseId)
}

func parseOrderId(orderId string) (int, int64) {
	vecOrderId := strings.Split(orderId, "FUNFIT")
	if len(vecOrderId) == 2 {
		productType, _ := strconv.ParseInt(vecOrderId[0], 10, 64)
		ts, _ := strconv.ParseInt(vecOrderId[1], 10, 64)
		return int(productType), ts
	}
	return 0, 0
}

// 课包的唯一标识符（用户id_场地id_课程id_教练id_获取课包的时间戳）
func genCoursePackageId(uid int64, ts int64) string {
	return fmt.Sprintf("cp_%d_%d", uid, ts)
}

func genCoursePackageSingleLessonID(uid int64, gymid int, courseId int, coachid int, ts int64) string {
	return fmt.Sprintf("sl_%d_%d_%d_%d_%d", uid, gymid, courseId, coachid, ts)
}

func GetTodayBegTs() int64 {
	t := time.Now()
	addTime := time.Date(t.Year(), t.Month(), t.Day(), 0, 0, 0, 0, t.Location())
	return addTime.Unix()
}

func GetTodayBegTsByTs(givenTimestamp int64) int64 {
	// 将时间戳转换为time.Time对象
	givenTime := time.Unix(givenTimestamp, 0)

	// 获取该日期的零点时间
	midnightTime := time.Date(givenTime.Year(), givenTime.Month(), givenTime.Day(), 0, 0, 0, 0, givenTime.Location())

	// 将零点时间转换为时间戳
	midnightTimestamp := midnightTime.Unix()

	return midnightTimestamp
}

// 获取调用者的文件名和函数名
func getCallerInfo(skip int) (string, string) {
	pc, file, _, ok := runtime.Caller(skip)
	if !ok {
		return "unknown", "unknown"
	}
	fn := runtime.FuncForPC(pc)
	if fn == nil {
		return "unknown", "unknown"
	}
	return path.Base(file), fn.Name()
}

// 包装 fmt.Printf，增加文件名和函数名打印
func Printf(format string, args ...interface{}) {
	// 这里传递 2 以获取更上层的调用者信息
	fileName, fullFuncName := getCallerInfo(2)

	var funcName string
	vecFullFuncName := strings.Split(fullFuncName, ".")
	if len(vecFullFuncName) > 0 {
		funcName = vecFullFuncName[len(vecFullFuncName)-1]
	} else {
		funcName = fullFuncName
	}
	format = fmt.Sprintf("[%s:%s] %s\n", fileName, funcName, format)
	fmt.Printf(format, args...)
}

func CalculateDaysSinceTimestamp(timestamp int64) int {
	// 将时间戳转换为 time.Time 对象
	startTime := time.Unix(timestamp, 0)

	// 获取当前时间
	currentTime := time.Now()

	// 计算两个时间之间的天数差
	days := int(currentTime.Sub(startTime).Hours() / 24)

	return days
}

func GetTodayEndTs() int64 {
	// 获取当前时间
	now := time.Now()

	// 创建当天零点的时间
	midnight := time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location())

	// 加一天，得到次日零点的时间
	nextMidnight := midnight.Add(24 * time.Hour)

	// 返回次日零点的时间戳
	return nextMidnight.Unix()
}

// 是否生产环境
func IsProd() bool {
	if os.Getenv("MiniprogramState") == "formal" {
		return true
	}
	return false
}

// 是否测试环境
func IsTrial() bool {
	if os.Getenv("MiniprogramState") == "trial" {
		return true
	}
	return false
}

// 打开多门店
func OpenMultiGym() bool {
	if os.Getenv("OpenMultiGym") == "1" {
		return true
	}
	return false
}

func uniqueVec(vecID *[]string) {
	tmpMap := make(map[string]int)
	for _, id := range *vecID {
		tmpMap[id] = 1
	}
	tmpVecID := make([]string, 0)
	for key, _ := range tmpMap {
		tmpVecID = append(tmpVecID, key)
	}
	*vecID = tmpVecID
	return
}

func uniqueVecCoach(vecID *[]model.CoachModel) {
	tmpMap := make(map[model.CoachModel]int)
	for _, id := range *vecID {
		tmpMap[id] = 1
	}
	tmpVecID := make([]model.CoachModel, 0)
	for key, _ := range tmpMap {
		tmpVecID = append(tmpVecID, key)
	}
	*vecID = tmpVecID
	return
}

func GetAllGymIds(gymIDs string) []int {
	var rsp []int
	if len(gymIDs) == 0 {
		return rsp
	}

	vecStrGymId := strings.Split(gymIDs, ",")
	for _, v := range vecStrGymId {
		nGynId, err := strconv.ParseInt(v, 10, 64)
		if err != nil {
			Printf("ParseInt err, err:%+v gymIDs:%s\n", err, gymIDs)
			continue
		}
		rsp = append(rsp, int(nGynId))
	}
	return rsp
}

func GetAllMapGymIds(gymIDs string) map[int]bool {
	rsp := make(map[int]bool)
	if len(gymIDs) == 0 {
		return rsp
	}

	vecStrGymId := strings.Split(gymIDs, ",")
	for _, v := range vecStrGymId {
		nGymId, err := strconv.ParseInt(v, 10, 64)
		if err != nil {
			Printf("ParseInt err, err:%+v gymIDs:%s\n", err, gymIDs)
			continue
		}
		rsp[int(nGymId)] = true
	}
	return rsp
}

func GetGymIdsByCoachId(coachId int) ([]int, error) {
	var rsp []int
	stCoachModel, err := dao.ImpCoach.GetCoachById(coachId)
	if err != nil {
		return rsp, err
	}
	if len(stCoachModel.GymIDs) == 0 {
		return rsp, nil
	}

	vecStrGymId := strings.Split(stCoachModel.GymIDs, ",")
	for _, v := range vecStrGymId {
		nGynId, err := strconv.ParseInt(v, 10, 64)
		if err != nil {
			Printf("ParseInt err, err:%+v gymIDs:%s\n", err, stCoachModel.GymIDs)
			continue
		}
		rsp = append(rsp, int(nGynId))
	}
	return rsp, nil
}

// GetCoachListByGymIdNew 根据健身房ID获取教练列表(不会对教练可见性做处理，需要调用方自己处理)
func GetCoachListByGymIdNew(reqGymId int) ([]model.CoachModel, error) {
	var rsp []model.CoachModel
	mapCoach := make(map[int][]model.CoachModel)
	vecCoachModel, err := dao.ImpCoach.GetCoachAll()
	if err != nil {
		return rsp, err
	}

	// 将教练按健身房ID分组
	for _, coach := range vecCoachModel {
		vecGymOfCoach := GetAllGymIds(coach.GymIDs)
		for _, gymId := range vecGymOfCoach {
			mapCoach[gymId] = append(mapCoach[gymId], coach)
		}
	}

	// 对每个健身房的教练列表按Priority降序排序
	for gymId, coaches := range mapCoach {
		sort.Slice(coaches, func(i, j int) bool {
			return coaches[i].Priority > coaches[j].Priority // 降序排列
		})
		mapCoach[gymId] = coaches
	}

	return mapCoach[reqGymId], nil
}

package model
// UserModel 用户模型 // UserInfo 用于匹配 user_info 表的字段 type UserInfoModel struct { UserID int64 `json:"user_id"` //用户uid WechatID string `json:"wechat_id"` //微信openid PhoneNumber *string `json:"phone_number" gorm:"default:null"` //手机号 Nick string `json:"nick,omitempty"` //昵称 HeadPic string `json:"head_pic"` //头像 Gender int `json:"gender"` //"0=男", "1=女", "2=other" Age int `json:"age"` //年龄 Weight int `json:"weight"` //体重 Height int `json:"height"` //身高 FitnessExperience int `json:"fitness_experience"` //健身经验（初级=1，中级=2，高级=3） FitnessGoal int `json:"fitness_goal"` //健身目标（1=减脂减重 2=增肌增重 3=塑型体态） DesiredWeight int `json:"desired_weight"` //期望体重 TimeFrame int `json:"time_frame"` //达成目标时间（1=慢一点但稳定 2=正常速度 3=越快真好） PreferredBodyPart string `json:"preferred_body_part"` //最期望增强部位 WeeklyExerciseFrequency int `json:"weekly_exercise_frequency"` //每周运动次数（频次1~2次/周=1，频次3~4次/周=2，频次5~7次/周=3） PreferredPriceRange int `json:"preferred_price_range"` //偏好价格档位(对应的体验课程id) PreferredLocationID int `json:"preferred_location_id"` //偏好健身房场地ID VipType int `json:"vip_type"` //vip订阅类型 0=非会员 1=体验会员 2=付费年费会员 VipExpiredTs int64 `json:"vip_expired_ts"` //vip过期时间 IsCoach bool `json:"is_coach"` //是否教练 CoachId int `json:"coach_id"` //如果是教练，关联的教练id HeadPicSafeStatus int `json:"head_pic_safe_status"` //头像审核结果(参考 Enum_HeadPic_Check) HeadPicWaitSafe string `json:"head_pic_wait_safe"` //等待审核的头像 HeadPicSafeTraceId string `json:"head_pic_safe_trace_id"` //等待审核的traceid，用户和异步回调匹配 RegistTs int64 `json:"regist_ts"` //用户注册时间 BeVipTs int64 `json:"be_vip_ts"` //成为订阅会员的时间 LastLoginTs int64 `json:"last_login_ts"` //上次登录时间（目前只记录教练的） HasShownNoStoreHint bool `json:"has_shown_no_store_hint"` //是否展示过未覆盖门店提醒 BeVipFromType int `json:"be_vip_from_type"` //成为订阅会员的方式 VipPassCardType int `json:"vip_pass_card_type"` //通卡会员类型 0=非通卡会员 1=体验通卡会员 2=付费通卡会员月卡 VipPassCardExpiredTs int64 `json:"vip_pass_card_expired_ts"` //通卡会员过期时间 BeVipPassCardTs int64 `json:"be_vip_pass_card_ts"` //成为通卡订阅会员的时间 BindPassCardGymId int `json:"bind_pass_card_gym_id"` //通卡场地端，用户 RecPassCardGymId int `json:"rec_pass_card_gym_id"` //通卡主页推荐的场地 IsOfficialAssistant bool `json:"is_official_assistant"` //是否官方小助理，展示特定的运营操作入口 //IsFirstTrailBlock bool `json:"is_first_trail_block"` //是否需要展示，首次约课加小助理微信的阻断 RemoveTrailBlockTs int64 `json:"remove_trail_block_ts"` //顾问是设置解除加小助理微信的阻断的时间，大于0表示设置过解除阻断 }
const ( Enum_VipType_Non int = iota // 0 = 非会员 Enum_VipType_Trial // 1 = 体验会员 Enum_VipType_PaidYear // 2 = 付费年费会员 )
const ( Enum_VipPassCardType_Non int = iota // 0 = 非会员 Enum_VipPassCardType_Trial // 1 = 通卡体验会员 Enum_VipPassCardType_PaidMonth // 2 = 通卡付费会员月卡 )
const ( Enum_HeadPic_Check_Non int = iota // 0 = 无审核状态 Enum_HeadPic_Check_Ing // 1 = 审核中 Enum_HeadPic_Check_Pass // 2 = 审核通过 Enum_HeadPic_Check_Deny // 3 = 审核拒绝 )
const ( Enum_BE_VIP_FROM_TYPE_Non int = iota // 0 = 无审核状态 Enum_BE_VIP_FROM_TYPE_BUY_FROM_REC // 线下完成体验课，通过顾问或教练分享，直接购买课包 )

